<?phpsession_start();require_once '../config/database.php';if (!isset($_SESSION['user_id'])) {    header('Location: ../login.php');    exit;}if (!isset($_GET['id'])) {    die('Waybill ID missing.');}$id = (int)$_GET['id'];$stmt = $pdo->prepare("    SELECT        w.*,        e.reporting_marks,        e.road_number    FROM waybills w    JOIN equipment e        ON w.equipment_id = e.id    WHERE w.id = :id    LIMIT 1");$stmt->execute([    'id' => $id]);$waybill = $stmt->fetch(PDO::FETCH_ASSOC);if (!$waybill) {    die('Waybill not found.');}$cycleStmt = $pdo->prepare("    SELECT        wc.*,        oi.industry_name AS origin_name,        di.industry_name AS destination_name    FROM waybill_cycles wc    LEFT JOIN industries oi        ON wc.origin_industry_id = oi.id    LEFT JOIN industries di        ON wc.destination_industry_id = di.id    WHERE wc.waybill_id = :waybill_id    AND wc.cycle_number = :cycle_number    LIMIT 1");$cycleStmt->execute([    'waybill_id' => $id,    'cycle_number' => $waybill['current_cycle']]);$cycle = $cycleStmt->fetch(PDO::FETCH_ASSOC);if (!$cycle) {    die('Waybill cycle not found.');}?><?php include '../includes/header.php'; ?><title>Print Waybill</title><style>body {    background:#f5f5f5;}.print-controls {    text-align:center;    margin:20px;}.waybill {    width:2.25in;    height:3.50in;    margin:20px auto;    background:#fff;    border:2px solid #000;    box-shadow:0 0 10px rgba(0,0,0,.15);    overflow:hidden;    font-family:Arial, Helvetica, sans-serif;}.waybill-header {    background:#fff7a8;    border-bottom:2px solid #000;    text-align:center;    font-weight:bold;    font-size:14px;    padding:6px;}.waybill-table {    width:100%;    border-collapse:collapse;}.waybill-table td {    border:1px solid #000;    padding:5px;    font-size:11px;    vertical-align:top;}.label-cell {    width:32%;    font-weight:bold;    background:#f8f8f8;}.value-cell {    width:68%;}.blank-space {    height:1.25in;}@media print {    .print-controls,    .navbar,    footer {        display:none !important;    }    body {        background:#fff;    }    .waybill {        margin:0;        box-shadow:none;    }}</style></head><body><?php include '../includes/navbar.php'; ?><div class="print-controls"><ahref="view.php?id=<?php echo $waybill['id']; ?>"class="btn btn-secondary me-2">Back to Waybill</a><buttononclick="window.print();"class="btn btn-primary">Print Waybill</button></div><div class="waybill"><div class="waybill-header">WAYBILL</div><table class="waybill-table"><tr>    <td class="label-cell">Car</td>    <td class="value-cell">        <?php        echo htmlspecialchars(            $waybill['reporting_marks']            . ' '            . $waybill['road_number']        );        ?>    </td></tr><tr>    <td class="label-cell">Cycle</td>    <td class="value-cell">        <?php        echo $waybill['current_cycle'];        ?>        of        <?php        echo $waybill['cycle_count'];        ?>    </td></tr><tr>    <td class="label-cell">Origin</td>    <td class="value-cell">        <?php echo htmlspecialchars($cycle['origin_name'] ?? ''); ?>    </td></tr><tr>    <td class="label-cell">Dest.</td>    <td class="value-cell">        <?php echo htmlspecialchars($cycle['destination_name'] ?? ''); ?>    </td></tr><tr>    <td class="label-cell">Commodity</td>    <td class="value-cell">        <?php echo htmlspecialchars($cycle['commodity'] ?? ''); ?>    </td></tr><tr>    <td class="label-cell">Route</td>    <td class="value-cell">        <?php echo htmlspecialchars($cycle['route'] ?? 'Direct'); ?>    </td></tr><tr>    <td class="label-cell">Status</td>    <td class="value-cell">        <?php echo htmlspecialchars($cycle['status'] ?? ''); ?>    </td></tr></table><div class="blank-space"></div></div><?php include '../includes/footer.php'; ?>